SELECT baseline.bldg_id, baseline."in.nhgis_tract_gisjoin", baseline.state FROM (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade = 0) AS baseline WHERE baseline.state IN ('CO', 'NM') AND (baseline.bldg_id, baseline."in.nhgis_tract_gisjoin", baseline.state) IN (SELECT upgrade.bldg_id, upgrade."in.nhgis_tract_gisjoin", upgrade.state FROM (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade != 0) AS upgrade WHERE upgrade.upgrade IN (1, 2) AND upgrade.applicability = true GROUP BY upgrade.bldg_id, upgrade."in.nhgis_tract_gisjoin", upgrade.state HAVING count(distinct(upgrade.upgrade)) = 2)